#[test]
fn test_start_activity_validity() {
    let log = load_event_log_json("running-example.json");

    let dfg = build_dfg_from_log(&log, "activity");

    // Start activities should exist in the activity set
    for start_act in &dfg.start_activities {
        assert!(
            dfg.activities.contains(&start_act.activity),
            "Start activity {} should be in activities",
            start_act.activity
        );
    }
}

