#[test]
fn test_dfg_completeness() {
    let log = load_event_log_json("running-example.json");

    let dfg = build_dfg_from_log(&log, "activity");

    // Verify DFG structure is complete
    assert!(!dfg.activities.is_empty(), "DFG should have activities");
    assert!(!dfg.edges.is_empty(), "DFG should have edges");
    assert!(
        !dfg.start_activities.is_empty(),
        "DFG should have start activities"
    );
    assert!(
        !dfg.end_activities.is_empty(),
        "DFG should have end activities"
    );
}

#[test]
fn test_trace_length_distribution() {
    let log = load_event_log_json("running-example.json");

    // Calculate trace length statistics
    let lengths: Vec<usize> = log.traces.iter().map(|t| t.events.len()).collect();

    let min_length = *lengths.iter().min().unwrap_or(&0);
    let max_length = *lengths.iter().max().unwrap_or(&0);
    let avg_length = if !lengths.is_empty() {
        lengths.iter().map(|&x| x).sum::<usize>() as f64 / lengths.len() as f64
    } else {
        0.0
    };

    assert!(min_length > 0, "Minimum trace length should be positive");
    assert!(
        max_length >= min_length,
        "Max length should be >= min length"
    );
    assert!(avg_length > 0.0, "Average trace length should be positive");
}

#[test]
fn test_event_attribute_completeness() {
    // Create a test log instead of loading from fixtures
    let mut log = EventLog::new();

    let mut trace = pictl::models::Trace::new();
    trace.attributes.insert(
        "case:concept:name".to_string(),
        AttributeValue::String("case1".to_string()),
    );

    let mut event1 = pictl::models::Event::new();
    event1.attributes.insert(
        "activity".to_string(),
        AttributeValue::String("A".to_string()),
    );
    event1.attributes.insert(
        "time:timestamp".to_string(),
        AttributeValue::String("2023-01-01T10:00:00Z".to_string()),
    );

    let mut event2 = pictl::models::Event::new();
    event2.attributes.insert(
        "activity".to_string(),
        AttributeValue::String("B".to_string()),
    );
    event2.attributes.insert(
        "time:timestamp".to_string(),
        AttributeValue::String("2023-01-01T11:00:00Z".to_string()),
    );

    trace.events.push(event1);
    trace.events.push(event2);
    log.traces.push(trace);

    // Verify all events have required attributes
    for trace in &log.traces {
        for event in &trace.events {
            assert!(
                event.attributes.contains_key("activity"),
                "Each event should have 'activity' attribute"
            );
            assert!(
                event.attributes.contains_key("time:timestamp"),
                "Each event should have 'time:timestamp' attribute"
            );
        }
    }
}

#[test]
fn test_case_id_uniqueness() {
    let log = load_event_log_json("running-example.json");

    // Verify case IDs are unique
    let mut case_ids = std::collections::HashSet::new();
    for trace in &log.traces {
        if let Some(AttributeValue::String(case_id)) = trace.attributes.get("case:concept:name") {
            assert!(
                case_ids.insert(case_id.clone()),
                "Case ID {} should be unique",
                case_id
            );
        }
    }
}

#[test]
fn test_activity_coverage() {
    let log = load_event_log_json("running-example.json");

    // Verify every activity appears in at least one edge
    let dfg = build_dfg_from_log(&log, "activity");

    for activity in &dfg.activities {
        let appears_in_edges = dfg
            .edges
            .iter()
            .any(|e| &e.from == activity || &e.to == activity);
        let is_start = dfg.start_activities.iter().any(|a| &a.activity == activity);
        let is_end = dfg.end_activities.iter().any(|a| &a.activity == activity);

        assert!(
            appears_in_edges || is_start || is_end,
            "Activity {} should appear in edges or be start/end",
            activity
        );
    }
}
